  2	import { ResourceYAMLEditor } from '@openshift-console/dynamic-plugin-sdk';
  3	import { Button, PageSection, Title, Wizard, WizardStep, WizardStepType } from '@patternfly/react-core';
  4	import { RJSFSchema } from '@rjsf/utils';
  5	import validator from '@rjsf/validator-ajv8';
  6	import _ from 'lodash';
  7	import React, { FC } from 'react';
  8	import { useTranslation } from 'react-i18next';
  9	import { ContextSingleton } from '../../utils/context';
 10	import { flowMetricNewPath, navigateTo, useNavigate, useParams } from '../../utils/url';
 11	import { safeYAMLToJS } from '../../utils/yaml';
 12	import { flowMetricUISchema } from './config/uiSchema';
 13	import { DynamicForm } from './dynamic-form/dynamic-form';
 14	import { ErrorTemplate } from './dynamic-form/templates';
 15	import './forms.css';
 16	import ResourceWatcher, { Consumer } from './resource-watcher';
 17	import { getFilteredUISchema } from './utils';
 18	
 19	export type FlowMetricWizardProps = {
 20	  name?: string;
 21	};
 22	
 23	const defaultPaths = ['metadata.namespace', 'metadata.name'];
 24	
 25	export const FlowMetricWizard: FC<FlowMetricWizardProps> = props => {
 26	  const { t } = useTranslation('plugin__netobserv-plugin');
 27	  const params = useParams<{ name?: string; namespace?: string }>();
 28	  const navigate = useNavigate();
 29	  const [schema, setSchema] = React.useState<RJSFSchema | null>(null);
 30	
 31	  const [data, setData] = React.useState<any>(null);
 32	  const [paths, setPaths] = React.useState<string[]>(defaultPaths);
 33	
 34	  const form = React.useCallback(
 35	    (errors?: string[]) => {
 36	      if (!schema) {
 37	        return <></>;
 38	      }
 39	      const filteredSchema = getFilteredUISchema(flowMetricUISchema, paths);
 40	      return (
 41	        <DynamicForm
 42	          formData={data}
 43	          schema={schema}
 44	          uiSchema={filteredSchema} // see if we can regenerate this from CSV
 45	          validator={validator}
 46	          onChange={event => {
 47	            setData(event.formData);
 48	          }}
 49	          errors={errors}
 50	          skipDefaults
 51	        />
 52	      );
 53	    },
 54	    [data, paths, schema]
 55	  );
 56	
 57	  const onStepChange = React.useCallback((_event: React.MouseEvent<HTMLButtonElement>, step: WizardStepType) => {
 58	    switch (step.id) {
 59	      case 'overview':
 60	        setPaths(defaultPaths);
 61	        break;
 62	      case 'metric':
 63	        setPaths(['spec.metricName', 'spec.type', 'spec.valueField', 'spec.labels', 'spec.buckets']);
 64	        break;
 65	      case 'data':
 66	        setPaths(['spec.remap', 'spec.direction', 'spec.filters']);
 67	        break;
 68	      default:
 69	        setPaths([]);
 70	    }
 71	  }, []);
 72	
 73	  return (
 74	    <ResourceWatcher
 75	      group="flows.netobserv.io"
 76	      version="v1alpha1"
 77	      kind="FlowMetric"
 78	      name={params.name || props.name}
 79	      namespace={params.namespace || 'default'}
 80	      onSuccess={() => {
 81	        navigate(-1);
 82	      }}
 83	      defaultFrom="CRD"
 84	    >
 85	      <Consumer>
 86	        {ctx => {
 87	          // first init schema & data when watch resource query got results
 88	          if (schema == null) {
 89	            setSchema(ctx.schema);
 90	          }
 91	          if (data == null) {
 92	            setData(ctx.data);
 93	          }
 94	          return (
 95	            <PageSection id="pageSection">
 96	              <div id="pageHeader">
 97	                <Title headingLevel="h1" size="2xl">
 98	                  {t('Network Observability FlowMetric setup')}
 99	                </Title>
100	              </div>
101	              <div id="wizard-container">
102	                <Wizard
103	                  id="flowMetricWizard"
104	                  onStepChange={onStepChange}
105	                  onSave={() => ctx.onSubmit(data)}
106	                  onClose={() => navigateTo('/')}
107	                >
108	                  <WizardStep name={t('Overview')} id="overview">
109	                    <span className="co-pre-line">
110	                      {t(
111	                        // eslint-disable-next-line max-len
112	                        'You can create custom metrics out of the network flows using the FlowMetric API. A FlowCollector resource must be created as well in order to produce the flows. Each flow consists in a set of fields with values, such as source name and destination name. These fields can be leveraged as Prometheus labels to enable customized metrics and dashboards.'
113	                      )}
114	                      <br />
115	                      <br />
116	                      {t(
117	                        // eslint-disable-next-line max-len
118	                        'This simplified setup guides you through the common aspects of the FlowMetric configuration. For advanced configuration, please use YAML or the '
119	                      )}
120	                      <Button
121	                        id="open-flow-metrics-form"
122	                        data-test-id="open-flow-metrics-form"
123	                        className="no-padding"
124	                        variant="link"
125	                        onClick={() => navigateTo(flowMetricNewPath)}
126	                      >
127	                        {t('FlowMetric form')}
128	                      </Button>
129	                      {'.'}
130	                      <br /> <br />
131	                      {t('Resource configuration')}
132	                    </span>
133	                    {form(ctx.errors)}
134	                  </WizardStep>
135	                  <WizardStep name={t('Metric')} id="metric">
136	                    {form(ctx.errors)}
137	                  </WizardStep>
138	                  <WizardStep name={t('Data')} id="data">
139	                    {form(ctx.errors)}
140	                  </WizardStep>
141	                  <WizardStep
142	                    name={t('Review')}
143	                    id="review-step"
144	                    body={{ className: 'wizard-editor-container' }}
145	                    footer={ContextSingleton.isStandalone() ? undefined : <></>}
146	                  >
147	                    <ResourceYAMLEditor
148	                      initialResource={data}
149	                      onSave={content => {
150	                        const updatedData = safeYAMLToJS(content);
151	                        setData(updatedData);
152	                        ctx.onSubmit(updatedData);
153	                      }}
154	                    />
155	                    <>{!_.isEmpty(ctx.errors) && <ErrorTemplate errors={ctx.errors} />}</>
156	                  </WizardStep>
157	                </Wizard>
158	              </div>
159	            </PageSection>
160	          );
161	        }}
162	      </Consumer>
163	    </ResourceWatcher>
164	  );
165	};
166	
167	export default FlowMetricWizard;

